    17→
    18→interface ProCardProps {
    19→    project?: Project;
    20→    isNew?: boolean;
    21→    onClick?: () => void;
    22→    onSettings?: (e: React.MouseEvent) => void;
    23→    className?: string;
    24→}
    25→
    26→// Decision color mapping for top accent band
    27→const DECISION_COLORS: Record<string, string> = {
    28→    GO: "#10B981",
    29→    EXPLORE: "#F59E0B",
    30→    PARK: "#6B7280",
    31→    KILL: "#EF4444",
    32→    DRAFT: "#5D5C5B",
    33→};
    34→
    35→export function ProCard({ project, isNew, onClick, onSettings, className }: ProCardProps) {
    36→    if (isNew) {
    37→        return (
    38→            <div
    39→                onClick={onClick}
    40→                className={cn(
    41→                    "group relative w-full aspect-[4/3] cursor-pointer",
    42→                    "bg-[--color-bg-card] rounded-[--radius-2xl] border border-dashed border-[--color-border-default]",
    43→                    "hover:border-[--color-border-strong] hover:bg-[--color-bg-card-hover]",
    44→                    "transition-all duration-200 flex flex-col items-center justify-center gap-4",
    45→                    className
    46→                )}
    47→            >
    48→                <div className="h-12 w-12 rounded-full bg-[--color-bg-card-hover] border border-[--color-border-default] flex items-center justify-center group-hover:border-[--color-border-strong] transition-all duration-300">
    49→                    <Plus className="w-5 h-5 text-[--color-text-muted] group-hover:text-[--color-text-primary] transition-colors" />
    50→                </div>
    51→                <span className="text-xs font-bold text-[--color-text-muted] group-hover:text-[--color-text-secondary] uppercase tracking-widest transition-colors">
    52→                    Nouveau Projet
    53→                </span>
    54→            </div>
    55→        );
    56→    }
    57→
    58→    if (!project) return null;
    59→
    60→    const decision = project.recommendation || "DRAFT";
    61→    const score = project.globalScore || 0;
    62→    const accentColor = project.color || DECISION_COLORS[decision] || DECISION_COLORS.DRAFT;
    63→
    64→    return (
    65→        <div
    66→            onClick={onClick}
    67→            className={cn(
    68→                "group relative w-full aspect-[4/3] cursor-pointer",
    69→                "bg-[--color-bg-card] rounded-[--radius-2xl] border border-[--color-border-default] overflow-hidden",
    70→                "hover:bg-[--color-bg-card-hover] hover:border-[--color-border-strong]",
    71→                "transition-all duration-300",
    72→                className
    73→            )}
    74→        >
    75→            {/* Color accent band at top */}
    76→            <div
    77→                className="absolute top-0 left-0 right-0 h-[3px]"
    78→                style={{ backgroundColor: accentColor }}
    79→            />
    80→
    81→            {/* Settings button — top right, appears on hover */}
    82→            {onSettings && (
    83→                <button
    84→                    onClick={(e) => {
    85→                        e.stopPropagation();
    86→                        onSettings(e);
    87→                    }}
    88→                    className="absolute top-4 right-4 z-20 opacity-0 group-hover:opacity-100 transition-opacity duration-200 h-8 w-8 rounded-full bg-black/40 backdrop-blur-sm flex items-center justify-center text-[--color-text-muted] hover:text-[--color-text-primary]"
    89→                >
    90→                    <Settings className="w-3.5 h-3.5" />
    91→                </button>
    92→            )}
    93→
    94→            <div className="p-8 flex flex-col h-full relative z-10">
    95→                {/* Header: Folder icon + Score */}
    96→                <div className="flex justify-between items-start mb-4">
    97→                    <div
    98→                        className="h-10 w-10 rounded-xl bg-[--color-bg-card-hover] flex items-center justify-center"
    99→                        style={{ borderColor: accentColor }}
   100→                    >
   101→                        <Folder className="w-4 h-4 text-[--color-text-muted]" />
   102→                    </div>
   103→
   104→                    {/* Score with /100 context */}
   105→                    <div className="text-right">
   106→                        <span className={cn(
   107→                            "text-2xl font-light tabular-nums tracking-tight",
   108→                            score >= 70 ? "text-[--color-text-primary]" : "text-[--color-text-secondary]"
   109→                        )}>
   110→                            {score}
   111→                        </span>
   112→                        <span className="text-xs text-[--color-text-muted] ml-0.5">/100</span>
   113→                    </div>
   114→                </div>
   115→
   116→                {/* Body */}
   117→                <div className="mt-2 mb-auto">
   118→                    <h3 className="text-lg font-semibold text-[--color-text-primary] leading-tight mb-2 line-clamp-2 group-hover:text-[--color-text-primary] transition-colors">
   119→                        {project.title || project.text}
   120→                    </h3>
   121→                    <p className="text-sm text-[--color-text-muted] line-clamp-3 leading-relaxed">
   122→                        {project.description || "Aucune description disponible."}
   123→                    </p>
   124→                </div>
   125→
   126→                {/* Footer: Date + Badge */}
   127→                <div className="mt-4 pt-4 border-t border-[--color-border-subtle] flex items-center justify-between">
   128→                    <span className="flex items-center gap-2 text-[10px] font-medium text-[--color-text-muted] group-hover:text-[--color-text-secondary] transition-colors uppercase tracking-wider">
   129→                        <Clock className="w-3 h-3" />
   130→                        {new Date(project.timestamp).toLocaleDateString()}
   131→                    </span>
   132→                    <div className="flex items-center gap-2">
   133→                        <DecisionBadge decision={decision} className="text-[10px] px-2 py-0.5" />
   134→                        <div className="opacity-0 group-hover:opacity-100 transition-opacity duration-300">
   135→                            <ArrowUpRight className="w-4 h-4 text-[--color-text-secondary]" />
   136→                        </div>
   137→                    </div>
   138→                </div>
   139→            </div>
   140→        </div>
   141→    );
   142→}
