     3→import { useState, useEffect } from "react";
     4→import { cn } from "@/lib/utils";
     5→import { Check } from "lucide-react";
     6→import { Button } from "@/components/ui/button";
     7→import { Input } from "@/components/ui/input";
     8→import { DecisionBadge } from "@/components/ui/decision-badge";
     9→import {
    10→    Dialog,
    11→    DialogContent,
    12→    DialogHeader,
    13→    DialogTitle,
    14→    DialogFooter,
    15→} from "@/components/ui/dialog";
    16→import { useLanguageStore } from "@/store/language-store";
    17→
    18→const COLOR_PRESETS = [
    19→    { hex: "#6B7280", label: "Gray" },
    20→    { hex: "#F75105", label: "Orange" },
    21→    { hex: "#3B82F6", label: "Blue" },
    22→    { hex: "#8B5CF6", label: "Violet" },
    23→    { hex: "#10B981", label: "Emerald" },
    24→    { hex: "#F59E0B", label: "Amber" },
    25→    { hex: "#EF4444", label: "Red" },
    26→    { hex: "#EC4899", label: "Pink" },
    27→];
    28→
    29→interface DossierProject {
    30→    id: string;
    31→    title?: string;
    32→    text: string;
    33→    description?: string;
    34→    color?: string;
    35→    globalScore?: number;
    36→    recommendation?: string;
    37→    viabilityScore?: number;
    38→    classification?: string;
    39→}
    40→
    41→interface DossierSettingsDialogProps {
    42→    project: DossierProject;
    43→    open: boolean;
    44→    onOpenChange: (open: boolean) => void;
    45→    onSave: (updates: { title?: string; description?: string; color?: string }) => void;
    46→}
    47→
    48→export function DossierSettingsDialog({ project, open, onOpenChange, onSave }: DossierSettingsDialogProps) {
    49→    const { t } = useLanguageStore();
    50→    const d = (t?.workspace as any)?.dossiers;
    51→
    52→    const [title, setTitle] = useState(project.title || project.text || "");
    53→    const [description, setDescription] = useState(project.description || "");
    54→    const [color, setColor] = useState(project.color || "#6B7280");
    55→
    56→    useEffect(() => {
    57→        setTitle(project.title || project.text || "");
    58→        setDescription(project.description || "");
    59→        setColor(project.color || "#6B7280");
    60→    }, [project]);
    61→
    62→    const score = project.globalScore ?? project.viabilityScore;
    63→    const decision = project.recommendation ?? project.classification ?? "DRAFT";
    64→
    65→    function handleSave() {
    66→        onSave({ title, description, color });
    67→        onOpenChange(false);
    68→    }
    69→
    70→    return (
    71→        <Dialog open={open} onOpenChange={onOpenChange}>
    72→            <DialogContent className="bg-[--color-bg-card] border border-[--color-border-default] rounded-[24px] max-w-md p-0 gap-0">
    73→                <DialogHeader className="p-8 pb-0">
    74→                    <DialogTitle className="text-white text-lg font-semibold">
    75→                        {d?.settingsTitle || "Dossier Settings"}
    76→                    </DialogTitle>
    77→                </DialogHeader>
    78→
    79→                <div className="space-y-6 p-8">
    80→                    {/* Title */}
    81→                    <div className="space-y-2">
    82→                        <label className="text-xs font-bold uppercase tracking-[0.1em] text-[#F75105]">
    83→                            {d?.titleLabel || "Title"}
    84→                        </label>
    85→                        <Input
    86→                            value={title}
    87→                            onChange={(e) => setTitle(e.target.value)}
    88→                            className="h-10 bg-[--color-bg-secondary] border-[--color-border-default] text-white rounded-md focus:border-[#F75105] focus:ring-[3px] focus:ring-[rgba(247,81,5,0.1)]"
    89→                        />
    90→                    </div>
    91→
    92→                    {/* Description */}
    93→                    <div className="space-y-2">
    94→                        <label className="text-xs font-bold uppercase tracking-[0.1em] text-[#F75105]">
    95→                            {d?.descriptionLabel || "Description"}
    96→                        </label>
    97→                        <textarea
    98→                            value={description}
    99→                            onChange={(e) => setDescription(e.target.value)}
   100→                            placeholder={d?.descriptionPlaceholder || "Add a description..."}
   101→                            rows={3}
   102→                            className="w-full bg-[--color-bg-secondary] border border-[--color-border-default] text-white rounded-md px-3 py-2 text-sm placeholder:text-[#5D5C5B] focus:border-[#F75105] focus:ring-[3px] focus:ring-[rgba(247,81,5,0.1)] focus:outline-none resize-none"
   103→                        />
   104→                    </div>
   105→
   106→                    {/* Score & Decision (read-only) */}
   107→                    {score !== undefined && (
   108→                        <div className="space-y-2">
   109→                            <label className="text-xs font-bold uppercase tracking-[0.1em] text-[#F75105]">
   110→                                {d?.scoreLabel || "Score"}
   111→                            </label>
   112→                            <div className="flex items-center gap-4 p-4 bg-[--color-bg-secondary] rounded-md border border-[--color-border-default]">
   113→                                <span className={cn(
   114→                                    "text-2xl font-light tabular-nums",
   115→                                    score >= 70 ? "text-white" : "text-[#D2D3D4]"
   116→                                )}>
   117→                                    {score}<span className="text-sm text-[#5D5C5B] ml-0.5">/100</span>
   118→                                </span>
   119→                                <DecisionBadge decision={decision} />
   120→                            </div>
   121→                        </div>
   122→                    )}
   123→
   124→                    {/* Color Picker */}
   125→                    <div className="space-y-2">
   126→                        <label className="text-xs font-bold uppercase tracking-[0.1em] text-[#F75105]">
   127→                            {d?.colorLabel || "Color"}
   128→                        </label>
   129→                        <div className="flex gap-2.5">
   130→                            {COLOR_PRESETS.map((preset) => (
   131→                                <button
   132→                                    key={preset.hex}
   133→                                    onClick={() => setColor(preset.hex)}
   134→                                    className={cn(
   135→                                        "w-8 h-8 rounded-full border-2 flex items-center justify-center transition-colors",
   136→                                        color === preset.hex
   137→                                            ? "border-white"
   138→                                            : "border-transparent hover:border-[--color-border-strong]"
   139→                                    )}
   140→                                    style={{ backgroundColor: preset.hex }}
   141→                                    title={preset.label}
   142→                                >
   143→                                    {color === preset.hex && <Check className="w-3.5 h-3.5 text-white" />}
   144→                                </button>
   145→                            ))}
   146→                        </div>
   147→                    </div>
   148→                </div>
   149→
   150→                <DialogFooter className="p-8 pt-0">
   151→                    <Button
   152→                        variant="outline"
   153→                        onClick={() => onOpenChange(false)}
   154→                        className="bg-transparent border-[--color-border-default] text-[#D2D3D4] hover:bg-[--color-bg-card-hover] hover:border-[--color-border-strong] hover:text-white"
   155→                    >
   156→                        {d?.cancel || "Cancel"}
   157→                    </Button>
   158→                    <Button
   159→                        onClick={handleSave}
