                { id: "5", title: "Quantum Encryption Key", text: "Clé de chiffrement quantique", globalScore: 88, recommendation: "GO", timestamp: new Date(Date.now() - 500000000).toISOString(), isDemo: true, description: "Next-gen security infrastructure for fintech. Critical need in the post-quantum era." },
            ];
            setProjects(mocks);
        } else {
            setProjects(storedProjects);
        }
    }, []);

